using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change 1: EF Core 9 renamed the discriminator JSON property
            // from "Discriminator" to "$type". Existing 500K documents use "Discriminator",
            // and direct SQL queries reference c.Discriminator — preserve the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF Core 9 no longer includes the discriminator in the
            // JSON id value. Existing ids are "Product|123"; without this, EF Core 9
            // would generate just "123" and fail to find existing documents.
            entity.HasDiscriminatorInJsonId();

            // Breaking change 3: HasIndex is not supported by the Cosmos provider and
            // now throws at model building time. Cosmos indexing is configured via
            // indexing policy on the container, not through EF Core.
            // REMOVED: entity.HasIndex(p => p.Sku);
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

