using Microsoft.EntityFrameworkCore;
class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator" as the
        // discriminator property name in OnModelCreating (see ProductContext.cs).
        // Without that configuration, EF Core 9 would write "$type" instead, and this
        // query would return zero results against existing documents.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Breaking change 4: EF Core 9 Cosmos provider removed synchronous I/O.
        // ToList(), First(), Single(), etc. now throw InvalidOperationException.
        // All queries must use async equivalents.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

